    const tmpFile = path.join(tmpDir, `test-jsonfile-${Date.now()}.json`)

    const testData = { test: true }
    fs.writeFileSync(tmpFile, JSON.stringify(testData), 'utf8')

    // Use graceful-fs since that's what the module uses
    const gracefulFs = require('graceful-fs')
    const originalReadFile = gracefulFs.readFile
    let capturedOptions: any = null

    gracefulFs.readFile = (file: string, options: any, callback: Function) => {
      capturedOptions = options
      originalReadFile(file, options, callback)
    }

    try {
      await jsonfile.readFile(tmpFile, 'utf8')
      expect(capturedOptions).toHaveProperty('encoding', 'utf8')
    } finally {
      gracefulFs.readFile = originalReadFile
      fs.unlinkSync(tmpFile)
    }
  })
})
```

This approach uses a spy on graceful-fs to verify the encoding is passed. With the original code, `options` becomes `{ encoding: 'utf8' }` so `capturedOptions.encoding` is `'utf8'`. With the mutation, `options` becomes `{}` so `capturedOptions.encoding` is `undefined`.

